```class Solution {
    public int getKth(int lo, int hi, int k) {
        int[] powerArray = new int[hi - lo + 1];
        int power = calculatePower(lo, hi, powerArray);
        int kthElement = findKthElement(powerArray, k);
        return kthElement;
    }

    private int calculatePower(int lo, int hi, int[] powerArray) {
        int power = 0;
        for (int i = lo; i <= hi; i++) {
            powerArray[power] = i;
            power++;
        }
        return power;
    }

    private int findKthElement(int[] powerArray, int k) {
        int kthElement = powerArray[k - 1];
        return kthElement;
    }
}
